INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('state-drought-relief-program','State Drought Relief Program','SDRP','USDA Farm Service Agency','disaster_relief','Emergency support for producers with major weather-related crop losses in 2025-2026.','The State Drought Relief Program supports qualifying producers who experienced substantial drought-related losses and need near-term operating cash support to stabilize spring and summer production.','Contact your county USDA Service Center, complete producer loss documentation, submit acreage and production evidence, then sign final payment forms before the deadline.','{"requires_loss": true, "crop_types": null, "counties": "disaster_designated", "is_urgent": true, "beginning_farmer_priority": true}','2026-12-10','December 10, 2026',TRUE,'Up to $150,000 per operation','grant','https://www.fsa.usda.gov/programs-and-services/disaster-assistance-program/index','1-877-508-8364',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('farm-operating-loans','Farm Operating Loans','FBA','USDA Farm Service Agency','loan','Direct and guaranteed operating capital for producers facing disaster-related cash-flow pressure.','Farm Operating Loans provide working capital for seed, fertilizer, labor, and other operational inputs when farm cash flow is disrupted by drought and market volatility.','Submit a direct loan package through your USDA Service Center including farm records, cash flow projections, and production plans.','{"requires_loss": false, "crop_types": null, "counties": "all", "is_urgent": false, "beginning_farmer_priority": true}','2026-11-30','Rolling intake through Nov 30, 2026',FALSE,'Up to FSA loan limits','loan','https://www.fsa.usda.gov/programs-and-services/farm-loan-programs/farm-operating-loans/index','1-877-508-8364',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('emergency-conservation-program','Emergency Conservation Program','ECP','USDA Farm Service Agency','conservation','Cost-share for restoring farmland damaged by natural disasters and severe drought.','ECP helps agricultural producers restore farmland and conservation structures damaged by disaster, including emergency water conservation and erosion control work.','File an ECP request at your local FSA office, document eligible damage, and complete approved conservation work to receive reimbursement.','{"requires_loss": true, "crop_types": null, "counties": "disaster_designated", "is_urgent": true, "beginning_farmer_priority": false}','2026-10-31','October 31, 2026',TRUE,'Up to 75% cost-share (90% for limited-resource producers)','cost_share','https://www.fsa.usda.gov/programs-and-services/conservation-programs/emergency-conservation/index','1-877-508-8364',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('conservation-reserve-program','Conservation Reserve Program','CRP','USDA Farm Service Agency','conservation','Annual rental payments for taking sensitive land out of production and improving resiliency.','CRP contracts provide annual rental payments and practice incentives for producers who enroll eligible land in conservation cover to reduce drought stress and improve soil health.','Meet with FSA to review eligible acreage and submit a CRP offer during signup windows.','{"requires_loss": false, "crop_types": null, "counties": "all", "is_urgent": false, "beginning_farmer_priority": false}','2026-08-15','General signup closes August 15, 2026',FALSE,'Annual rental plus practice incentives','annual_payment','https://www.fsa.usda.gov/programs-and-services/conservation-programs/conservation-reserve-program/index','1-877-508-8364',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('environmental-quality-incentives-program','Environmental Quality Incentives Program','EQIP','USDA Natural Resources Conservation Service','conservation','Technical and financial assistance for drought-resilient conservation practices.','EQIP supports on-farm conservation improvements such as irrigation upgrades, water management, grazing systems, and soil health practices that reduce drought vulnerability.','Work with NRCS to complete a conservation plan and submit an EQIP application at your local service center.','{"requires_loss": false, "crop_types": null, "counties": "all", "is_urgent": false, "beginning_farmer_priority": true}','2026-09-30','Batching date September 30, 2026',FALSE,'Practice-based cost share','cost_share','https://www.nrcs.usda.gov/programs-initiatives/eqip-environmental-quality-incentives','1-202-720-7246',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('farm-and-ranch-stress-assistance-network','Farm and Ranch Stress Assistance Network','FRSAN','USDA National Institute of Food and Agriculture','mental_health','Confidential stress, behavioral health, and referral support for farmers and ranchers.','FRSAN funds regionally coordinated stress assistance services including crisis support, counseling referrals, and producer-focused mental health outreach.','Call the regional hotline or connect through extension partners for confidential stress assistance and referral services.','{"requires_loss": false, "crop_types": null, "counties": "all", "is_urgent": true, "beginning_farmer_priority": false}','2027-01-31','Ongoing support access',TRUE,'No-cost support services','service','https://www.nifa.usda.gov/grants/programs/farm-and-ranch-stress-assistance-network-frsan','1-800-327-6243',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('emergency-commodity-assistance-program','Emergency Commodity Assistance Program','ECAP','USDA Farm Service Agency','commodity_support','Direct commodity assistance for market and input-cost disruptions affecting producers.','Emergency Commodity Assistance Program provides temporary direct assistance to commodity producers impacted by severe market and input-cost disruptions.','Submit eligible planted acreage and production records at your county FSA office during the announced signup period.','{"requires_loss": false, "crop_types": ["corn", "soybeans", "cotton", "wheat", "peanuts"], "counties": "all", "is_urgent": true, "beginning_farmer_priority": false}','2026-10-15','Signup closes October 15, 2026',TRUE,'Commodity-specific payment rates','direct_payment','https://www.fsa.usda.gov/programs-and-services/emergency-relief/index','1-877-508-8364',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
INSERT INTO programs (slug,name,acronym,agency,category,summary,description,how_to_apply,eligibility_rules,deadline,deadline_label,is_urgent,funding_amount,payment_type,apply_url,phone_number,active) VALUES ('conservation-stewardship-program','Conservation Stewardship Program','CSP','USDA Natural Resources Conservation Service','conservation','Performance-based payments for advanced whole-farm conservation improvements.','CSP helps producers build on existing conservation by adopting advanced stewardship activities that improve drought resilience, soil function, and water-use efficiency.','Complete a CSP self-screening and submit your application through NRCS before ranking deadlines.','{"requires_loss": false, "crop_types": null, "counties": "all", "is_urgent": false, "beginning_farmer_priority": true}','2026-09-30','Ranking deadline September 30, 2026',FALSE,'Annual stewardship payments','annual_payment','https://www.nrcs.usda.gov/programs-initiatives/csp-conservation-stewardship-program','1-202-720-1845',TRUE) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, acronym=EXCLUDED.acronym, agency=EXCLUDED.agency, category=EXCLUDED.category, summary=EXCLUDED.summary, description=EXCLUDED.description, how_to_apply=EXCLUDED.how_to_apply, eligibility_rules=EXCLUDED.eligibility_rules, deadline=EXCLUDED.deadline, deadline_label=EXCLUDED.deadline_label, is_urgent=EXCLUDED.is_urgent, funding_amount=EXCLUDED.funding_amount, payment_type=EXCLUDED.payment_type, apply_url=EXCLUDED.apply_url, phone_number=EXCLUDED.phone_number, active=EXCLUDED.active;
